[['SPY', 'QQQ', 'IWM'], {}, ['base_price]\n        for r in spy_returns[:-1]:\n            spy_prices.append(spy_prices[-1] * (1 + r))\n        data["SPY'], ['base_price]\n        for r in qqq_returns[:-1]:\n            qqq_prices.append(qqq_prices[-1] * (1 + r))\n        data["QQQ'], ['base_price]\n        for r in iwm_returns[:-1]:\n            iwm_prices.append(iwm_prices[-1] * (1 + r))\n        data["IWM'], ['market_vol_20d', 'market_trend_20d', 'dispersion_20d', 'corr_mean_20d'], [20], ['market_vol_20d'], [20, 0, '.', 'all()\n        \n        # Check that computation uses 20-day rolling window and sqrt(252) annualization\n        log_returns = np.log(sample_regime_prices / sample_regime_prices.shift(1))\n        portfolio_returns = log_returns.mean(axis=1)\n        expected_vol = portfolio_returns.rolling(window=20, min_periods=20).std() * np.sqrt(252)\n        \n        pd.testing.assert_series_equal(vol_result.iloc[20:], expected_vol.iloc[20:], check_names=False)\n\n    def test_market_trend_20d_computation(self, sample_regime_prices: pd.DataFrame):\n        "', 'Test market trend computation."', '\n        result = compute_regime_features(sample_regime_prices)\n        trend_result = result["market_trend_20d'], [20, 'expected_trend.iloc[20:], check_names=False)\n\n    def test_dispersion_20d_computation(self, sample_regime_prices: pd.DataFrame):\n        "', 'Test dispersion computation."', '\n        result = compute_regime_features(sample_regime_prices)\n        dispersion_result = result["dispersion_20d'], [20, 'expected_dispersion.iloc[20:], check_names=False)\n\n    def test_corr_mean_20d_computation(self, sample_regime_prices: pd.DataFrame):\n        "', 'Test mean pairwise correlation computation."', '\n        result = compute_regime_features(sample_regime_prices)\n        corr_result = result["corr_mean_20d'], [1], ['np.triu_indices(n_symbols, k=1)].mean()\n            if len(c) == n_symbols else np.nan\n        )\n        \n        pd.testing.assert_series_equal(corr_result.iloc[20:], expected_corr.iloc[20:], check_names=False)\n\n    def test_single_symbol_handling(self):\n        "', 'Test handling of single symbol case."', '\n        dates = pd.date_range("2023-01-01', 'periods=30, freq="D")\n        single_symbol_data = pd.DataFrame({\n            "SPY', 'np.random.lognormal(mean=5, sigma=0.2, size=30)\n        }, index=dates)\n        \n        result = compute_regime_features(single_symbol_data)\n        \n        # With single symbol, corr_mean_20d should be NaN\n        assert pd.isna(result["corr_mean_20d'], ['market_vol_20d'], [20, '.', 'all()\n        assert not pd.isna(result["market_trend_20d'], [20, '.', 'all()\n        assert not pd.isna(result["dispersion_20d'], [20, '.', 'all()\n\n    def test_empty_data_handling(self):\n        "', 'Test handling of empty input data."', '\n        empty_data = pd.DataFrame(columns=["SPY', 'QQQ', 'IWM'], ['market_vol_20d', 'market_trend_20d', 'dispersion_20d', 'corr_mean_20d'], ['market_vol_20d'], ['market_trend_20d'], ['dispersion_20d'], ['corr_mean_20d'], [10, 0], [20, 1], ['market_vol_20d'], [20, '.', 'all()\n            assert np.isfinite(result["market_trend_20d'], [20, '.', 'all()\n            assert np.isfinite(result["dispersion_20d'], [20, '.', 'all()\n            # corr_mean_20d might be NaN in some cases, which is acceptable\n        except Exception as e:\n            pytest.fail(f"Extreme values caused exception in regime feature computation: {e}']]